fn tuning_summary(tuning: Option<&OpenAiCompatibleTuning>) -> String {
    let Some(tuning) = tuning else {
        return "default".to_string();
    };
    let mut parts = Vec::new();
    if let Some(value) = tuning.reasoning_effort.as_deref() {
        parts.push(format!("reasoning_effort={value}"));
    }
    if let Some(value) = tuning.max_tokens {
        parts.push(format!("max_tokens={value}"));
    }
    if let Some(value) = tuning.temperature {
        parts.push(format!("temperature={value}"));
    }
    if let Some(value) = tuning.top_p {
        parts.push(format!("top_p={value}"));
    }
    if !tuning.extra_body.is_empty() {
        parts.push(format!("extra_body_keys={}", tuning.extra_body.len()));
    }
    if parts.is_empty() {
        "default".to_string()
    } else {
        parts.join(",")
    }
}

fn init_workspace(state_path: PathBuf, tentacles_root: PathBuf) -> Result<InitReport, String> {
    let state_existed = state_path.exists();
    let cwd = env::current_dir().map_err(|error| error.to_string())?;
    let mut state = HarnessState::load(&state_path).map_err(|error| error.to_string())?;
    let adapt = adapt_environment_with_bundled_seed_fallback(&mut state, cwd, tentacles_root);
    state.save(&state_path).map_err(|error| error.to_string())?;
    let files = init_files(&state_path)?;
    let state_arg = shell_arg(&state_path.to_string_lossy());
    let mut next = vec![
        format!("octopus --state {state_arg} chat \"describe your goal\""),
        format!("octopus --state {state_arg} skills"),
        format!("octopus --state {state_arg} pet"),
        format!("octopus --state {state_arg} need observe ."),
        format!("octopus --state {state_arg} doctor"),
    ];
    if let Some(env_file) = files
        .iter()
        .find(|file| file.path.ends_with("llm.env.example"))
    {
        let example = PathBuf::from(&env_file.path);
        let target = example.with_file_name("llm.env");
        next.push(format!(
            "copy {} to {}, fill it, then source {}",
            shell_arg(&env_file.path),
            shell_arg(&target.to_string_lossy()),
            shell_arg(&target.to_string_lossy())
        ));
    }
    Ok(InitReport {
        state_path: state_path.to_string_lossy().to_string(),
        state_existed,
        adapt,
        installed_profiles: state.installed_profiles,
        installed_tentacles: state
            .installed_tentacles
            .into_iter()
            .map(|tentacle| tentacle.id)
            .collect(),
        files,
        next,
    })
}

fn bootstrap_workspace(
    state_path: PathBuf,
    tentacles_root: PathBuf,
) -> Result<BootstrapReport, String> {
    let state_existed = state_path.exists();
    let cwd = env::current_dir().map_err(|error| error.to_string())?;
    let mut state = HarnessState::load(&state_path).map_err(|error| error.to_string())?;
    let files = init_files(&state_path)?;
    let adapt = adapt_environment_with_bundled_seed_fallback(
        &mut state,
        cwd.clone(),
        tentacles_root.clone(),
    );
    let seed_tentacles = bootstrap_seed_tentacles()
        .into_iter()
        .map(str::to_string)
        .collect::<Vec<_>>();
    let mut installed_tentacles = Vec::new();
    let mut skipped_tentacles = Vec::new();
    for tentacle_id in &seed_tentacles {
        let was_installed = state
            .installed_tentacles
            .iter()
            .any(|tentacle| tentacle.id == *tentacle_id);
        let _ = state.install_profile(tentacle_id);
        match install_manifest_with_bundled_fallback(&mut state, &tentacles_root, tentacle_id) {
            Ok(tentacle) if !was_installed => installed_tentacles.push(tentacle.id),
            Ok(_) => {}
            Err(error) => skipped_tentacles.push(format!("{tentacle_id}: {error}")),
        }
    }
    state.beat(200);
    state.save(&state_path).map_err(|error| error.to_string())?;
    let report = product_report(&state, &state_path)?;
    let state_arg = shell_arg(&state_path.to_string_lossy());
    let mut next = vec![
        format!("octopus --state {state_arg} report"),
        format!("octopus --state {state_arg} context observe ."),
        format!("octopus --state {state_arg} think swe-agent observe README.md"),
        format!("octopus --state {state_arg} think harness-repair-agent execute ."),
        format!("octopus --state {state_arg} need execute \"repair harness session\""),
        format!("octopus --state {state_arg} need observe README.md"),
        format!("octopus --state {state_arg} check swe-agent"),
        format!("octopus --state {state_arg} check harness-repair-agent"),
        format!("octopus --state {state_arg} pet"),
    ];
    next.extend(report.next.iter().cloned());
    next.sort();
    next.dedup();
    Ok(BootstrapReport {
        state_path: state_path.to_string_lossy().to_string(),
        state_existed,
        files,
        adapt,
        seed_tentacles,
        installed_tentacles,
        skipped_tentacles,
        report,
        next,
    })
}

fn default_first_run_objective() -> String {
    "make this project easier to use".to_string()
}

fn first_run_evidence_target() -> String {
    if Path::new("README.md").is_file() {
        "README.md".to_string()
    } else {
        ".".to_string()
    }
}

fn parse_first_run_args(args: &[String]) -> (bool, String) {
    let mut live = false;
    let mut objective = Vec::new();
    for arg in args {
        if arg == "--live" {
            live = true;
        } else {
            objective.push(arg.clone());
        }
    }
    let objective = if objective.is_empty() {
        default_first_run_objective()
    } else {
        objective.join(" ")
    };
    (live, objective)
}

fn first_run_report(
    state_path: PathBuf,
    objective: String,
    live: bool,
) -> Result<FirstRunReport, String> {
    let evidence_target = first_run_evidence_target();
    let bootstrap = bootstrap_workspace(state_path.clone(), default_tentacles_root())?;
    let mut loaded = HarnessState::load(&state_path).map_err(|error| error.to_string())?;
    let mut goal = Goal::new(objective.clone());
    add_goal_constraint(&mut goal, "keep tools outside the brain");
    loaded.goal = Some(goal.clone());
    loaded
        .save(&state_path)
        .map_err(|error| error.to_string())?;
    let starter = starter_report(
        &loaded,
        &state_path,
        default_tentacles_root(),
        Some(objective.clone()),
    )?;
    let mut harness = harness_for_need(loaded, &NeedKind::Observe)?;
    let feed = harness.feed(&[Need::new(NeedKind::Observe, evidence_target.clone())]);
    let trace_index = resolve_feed_trace_selector("latest", &harness.state)?;
    let feedback = harness.state.record_feed_feedback(
        trace_index,
        Status::Satisfied,
        "first run evidence".to_string(),
    )?;
    let beat = harness.state.beat(200);
    harness
        .state
        .save(&state_path)
        .map_err(|error| error.to_string())?;
    let product = product_report(&harness.state, &state_path)?;
    let preflight = preflight_report(&harness.state, &state_path, live)?;
    let doctor = doctor_report(&harness.state, state_path.clone())?;
    let state_arg = shell_arg(&state_path.to_string_lossy());
    let objective_arg = shell_arg(&objective);
    let mut next = vec![
        format!("octopus --state {state_arg} preflight"),
        format!("octopus --state {state_arg} preflight record"),
        format!("octopus --state {state_arg} start --open"),
        "octopus provider check".to_string(),
        format!("octopus --state {state_arg} self-iterate pr dangoZhang/Octopus \"review first-run evidence\""),
    ];
    if !live {
        next.push(format!(
            "octopus --state {state_arg} first-run --live {objective_arg}"
        ));
    }
    Ok(FirstRunReport {
        state_path: state_path.to_string_lossy().to_string(),
        objective,
        live,
        evidence_target,
        bootstrap,
        goal,
        starter,
        feed,
        feedback,
        beat,
        product,
        preflight,
        doctor,
        next,
    })
}

