fn metadata_value(metadata: &BTreeMap<String, String>, key: &str) -> String {
    metadata.get(key).cloned().unwrap_or_default()
}

fn repair_score_commands_from_metadata(metadata: &BTreeMap<String, String>) -> Option<Vec<String>> {
    let value = metadata.get("score_commands")?;
    let commands = value
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(|line| {
            metadata
                .get("feed_trace_index")
                .map(|index| line.replace("<trace-index>", index))
                .unwrap_or_else(|| line.to_string())
        })
        .collect::<Vec<_>>();
    (!commands.is_empty()).then_some(commands)
}

fn repair_next_need_from_feed(feed: &Feed) -> Option<GoalNeedSuggestion> {
    let query = feed
        .metadata
        .get("next_need_query")
        .or_else(|| feed.metadata.get("next_need"))?
        .trim();
    if query.is_empty() {
        return None;
    }
    let kind = feed
        .metadata
        .get("next_need_kind")
        .and_then(|value| parse_kind(value).ok())
        .unwrap_or(NeedKind::Verify);
    Some(GoalNeedSuggestion {
        kind,
        query: query.to_string(),
    })
}

fn product_report(state: &HarnessState, state_path: &Path) -> Result<ProductReport, String> {
    let status = state.status_report_with_state(Some(state_path));
    let cwd = env::current_dir().map_err(|error| error.to_string())?;
    let environment = EnvironmentReport::detect(&cwd);
    let manifests =
        inspect_tentacle_manifests_with_bundled_seed_fallback(&default_tentacles_root())?;
    let provider = provider_status_report();
    let provider_matrix = check_provider_matrix_record(Path::new(DEFAULT_PROVIDER_MATRIX_PATH))?;
    let profile_registry = profile_registry_report(state_path);
    let boundary = core_boundary::report(state_path);
    let field_trajectory = state.field_trajectory_report_with_state(Some(state_path))?;
    let field_pool = product_field_pool_report(&field_trajectory);
    let pet_exists = repo_root().join("docs/pet.html").exists();
    let app_exists = repo_root().join("docs/app.html").exists();
    let docs_exists = repo_root().join("docs/index.html").exists();
    let broken_manifests = manifests
        .iter()
        .filter(|manifest| !manifest.missing_entrypoints.is_empty())
        .map(|manifest| manifest.id.clone())
        .collect::<Vec<_>>();
    let broken_installed_seed_sources = collect_broken_installed_seed_sources(state);
    let runtime_kinds = manifests
        .iter()
        .flat_map(|manifest| manifest.runtime_kinds.iter().cloned())
        .collect::<BTreeSet<_>>();
    let required_surfaces = [
        "brain_prompt",
        "tool_meta",
        "runtime_code",
        "evolution_policy",
    ];
    let harness_surfaces_ready = manifests.iter().any(|manifest| {
        required_surfaces.iter().all(|surface| {
            manifest
                .evolution_surfaces
                .iter()
                .any(|item| item == surface)
        })
    });
    let provider_configured = provider.layers.iter().any(|layer| layer.configured);
    let provider_ready = provider_coverage_ready(&provider);
    let github_ready = state.active_grant("github", "dangoZhang/Octopus").is_some();

    let mut capabilities = vec![
        product_capability(
            "core_harness_boundary",
            if boundary.ok {
                "ready"
            } else {
                "needs_attention"
            },
            format!(
                "stable_rust={}, editable_harness={}, warnings={}",
                boundary.stable_rust.len(),
                boundary.editable_harness.len(),
                boundary.warnings.len()
            ),
            Some("octopus report"),
        ),
        product_capability(
            "clean_brain",
            "ready",
            "brain context is Goal + Mem + Need + Feed",
            Some("octopus context observe ."),
        ),
        product_capability(
            "context_inspection",
            "ready",
            "CLI, JSON, and native app expose clean-brain and tentacle context boundaries",
            Some("octopus context observe ."),
        ),
        product_capability(
            "clean_brain_explore",
            "ready",
            "Goal/Mem/Need/Feed exploration returns Need suggestions without tool execution",
            Some("octopus explore"),
        ),
        product_capability(
            "clean_brain_intent",
            "ready",
            "Goal/Mem/Need/Feed intent selection returns cognitive Needs without tool execution",
            Some("octopus brain --intent"),
        ),
        product_capability(
            "clean_brain_brief",
            "ready",
            "Goal/Mem/Need/Feed brief compacts clean context for the next model turn without tool execution",
            Some("octopus brain --brief"),
        ),
        product_capability(
            "clean_brain_align",
            "ready",
            "Goal/Mem/Need/Feed alignment checks Goal constraints and clean next Needs without Feed execution",
            Some("octopus brain --align"),
        ),
        product_capability(
            "clean_brain_agenda",
            "ready",
            "Goal/Mem/Need/Feed agenda returns cognitive priorities and clean Needs without Feed execution",
            Some("octopus brain --agenda"),
        ),
        product_capability(
            "clean_brain_scout",
            "ready",
            "Goal/Mem/Need/Feed scout maps assumptions, unknowns, directions, risks, and clean Needs without Feed execution",
            Some("octopus brain --scout"),
        ),
        product_capability(
            "clean_brain_deliberation",
            "ready",
            "Goal/Mem/Need/Feed deliberation returns observations, questions, options, risks, and clean Needs without Feed execution",
            Some("octopus brain --deliberate"),
        ),
        product_capability(
            "clean_brain_audit",
            "ready",
            "clean-brain Goal, agenda, and exploration reports flag implementation burden and expose only clean Needs for queueing",
            Some("octopus brain --live \"what should the brain ask next?\""),
        ),
        product_capability(
            "clean_brain_rewrite",
            "ready",
            "provider-backed or external-chat rewrite turns polluted model Needs into cognitive Needs before queueing",
            Some("octopus brain --rewrite --live --apply reply.json --save"),
        ),
        product_capability(
            "clean_brain_model_slots",
            "ready",
            "Goal, Intent, Brief, Align, Clarify, Agenda, Scout, Deliberate, Explore, Rewrite, and Need Queue review can use separate provider prefixes without changing brain context",
            Some("octopus provider status"),
        ),
        product_capability(
            "need_queue",
            "ready",
            format!(
                "{} pending clean-brain Need suggestions",
                status.need_queue_count
            ),
            Some("octopus explore --save"),
        ),
        product_capability(
            "need_queue_script",
            "ready",
            "writes pending clean-brain Needs into a reviewable Feed script without execution",
            Some("octopus needs script"),
        ),
        product_capability(
            "need_queue_review",
            "ready",
            "writes prompt, messages, review template, and optional live draft for pending Needs",
            Some("octopus needs session"),
        ),
        product_capability(
            "harness_repair_queue",
            if state
                .installed_tentacles
                .iter()
                .any(|tentacle| tentacle.id == "harness-repair-agent")
            {
                "ready"
            } else {
                "available"
            },
            "harness-repair Feed can queue the next clean-brain Need",
            Some("octopus repair ."),
        ),
        product_capability(
            "clean_brain_prompt",
            "ready",
            "exports pasteable Goal/Mem/Need/Feed messages for any chat model",
            Some("octopus brain"),
        ),
        product_capability(
            "external_brain_reply",
            "ready",
            "imports chat-model JSON into Goal or Need Queue without Feed execution",
            Some("octopus brain --apply reply.json --save"),
        ),
        product_capability(
            "brain_session",
            "ready",
            "writes prompt, messages, reply template, optional live draft, and apply command for external chat",
            Some("octopus brain --session"),
        ),
        product_capability(
            "tentacle_brains",
            if status.tentacles.is_empty() {
                "available"
            } else {
                "ready"
            },
            format!(
                "{} installed, {} manifests",
                status.tentacles.len(),
                manifests.len()
            ),
            Some("octopus install swe-agent"),
        ),
        product_capability(
            "runtime_neutral_harness",
            if harness_surfaces_ready {
                "ready"
            } else {
                "needs_manifest"
            },
            format!(
                "runtimes: {}; surfaces: {}",
                join_or_none(&runtime_kinds.iter().cloned().collect::<Vec<_>>()),
                required_surfaces.join(", ")
            ),
            Some("octopus manifests"),
        ),
        product_capability(
            "field_parallel_pool",
            if field_pool.field_count >= 8 {
                "ready"
            } else {
                "needs_field_packs"
            },
            format!(
                "{} peer slots, {} completed, sampled_slot={}",
                field_pool.field_count,
                field_pool.completed_fields,
                option_or_none(&field_pool.sampled_slot_field)
            ),
            Some("octopus fields summary"),
        ),
        product_capability(
            "profile_registry",
            if profile_registry.ok {
                "ready"
            } else {
                "invalid"
            },
            format!(
                "source={}, path={}, profiles={}",
                profile_registry.source, profile_registry.path, profile_registry.profile_count
            ),
            Some("octopus bootstrap"),
        ),
        product_capability(
            "three_hearts",
            if status.hearts.len() >= 3 {
                "ready"
            } else {
                "missing"
            },
            status
                .hearts
                .iter()
                .map(|beat| format!("{}={}", beat.name, beat.summary))
                .collect::<Vec<_>>()
                .join(", "),
            Some("octopus beat 200"),
        ),
        product_capability(
            "color_pet",
            if pet_exists { "ready" } else { "missing" },
            repo_root()
                .join("docs/pet.html")
                .to_string_lossy()
                .to_string(),
            Some("octopus pet"),
        ),
        product_capability(
            "native_html_app",
            if app_exists { "ready" } else { "missing" },
            repo_root()
                .join("docs/app.html")
                .to_string_lossy()
                .to_string(),
            Some("octopus start --open"),
        ),
        product_capability(
            "local_project_start",
            if app_exists { "ready" } else { "missing" },
            "start prepares local state, seed tentacles, heartbeat state, serves the native app, and can open it",
            Some("octopus start --open"),
        ),
        product_capability(
            "local_update",
            "ready",
            "dry-run update report plus explicit cargo install runner",
            Some("octopus update"),
        ),
        product_capability(
            "starter_panel",
            if app_exists { "ready" } else { "missing" },
            "native HTML app renders starter recommendations with evidence signals, choice feedback, install, check, and first-Need actions",
            Some("octopus starter \"build a clean-brain agent\""),
        ),
        product_capability(
            "local_bootstrap",
            "ready",
            "init, environment adaptation, seed tentacle install, heartbeat, and report in one command",
            Some("octopus bootstrap"),
        ),
        product_capability(
            "harness_apply_review",
            "ready",
            "harness beat recommendations can be granted and written as reviewable apply artifacts",
            Some("octopus evolve apply swe-agent 03-runtime-code"),
        ),
        product_capability(
            "harness_self_repair",
            if status
                .tentacles
                .iter()
                .any(|tentacle| tentacle.id == "harness-repair-agent")
            {
                "ready"
            } else {
                "available"
            },
            format!(
                "harness-repair-agent can turn signals into repair Feed; {} scored repair outcomes",
                status.repair_outcome_count
            ),
            Some("octopus install harness-repair-agent"),
        ),
        product_capability(
            "harness_learning",
            if status.harness_learning.source == "none" {
                "waiting_for_feedback"
            } else {
                "ready"
            },
            harness_learning_line(&status.harness_learning),
            Some(status.harness_learning.next_action.as_str()),
        ),
        product_capability(
            "goal_setting",
            "ready",
            "human goals and constraints can be set or refined without Feed execution",
            Some("octopus goal set --constraint \"keep tools outside the brain\" \"build a clean-brain agent\""),
        ),
        product_capability(
            "route_report",
            "ready",
            format!(
                "{} route scores, {} Feed traces",
                status.route_count, status.feed_trace_count
            ),
            Some("octopus routes observe ."),
        ),
        product_capability(
            "provider_layers",
            if provider_ready {
                "ready"
            } else if provider_configured {
                "configured"
            } else {
                "setup_needed"
            },
            provider
                .coverage
                .iter()
                .map(|coverage| {
                    format!(
                        "{} ready={} prefixes={}",
                        coverage.id,
                        coverage.ready,
                        join_or_none(&coverage.prefixes)
                    )
                })
                .collect::<Vec<_>>()
                .join("; "),
            Some("octopus provider status"),
        ),
        product_capability(
            "provider_matrix_record",
            if provider_matrix.passed {
                "ready"
            } else {
                "needs_record"
            },
            provider_matrix_check_evidence(&provider_matrix),
            Some("octopus provider matrix check"),
        ),
        product_capability(
            "self_iteration",
            if github_ready {
                "pr_ready"
            } else {
                "oauth_required"
            },
            state.self_iteration_plan("dangoZhang/Octopus", None).mode,
            Some("octopus self-iterate dangoZhang/Octopus"),
        ),
        product_capability(
            "docs_home",
            if docs_exists { "ready" } else { "missing" },
            "README story plus native docs homepage".to_string(),
            Some("open docs/index.html"),
        ),
    ];
    capabilities.sort_by(|left, right| left.id.cmp(&right.id));

    let mut gaps = Vec::new();
    let state_args = format!(" --state {}", shell_arg(&state_path.to_string_lossy()));
    if status.goal.is_none() {
        gaps.push(product_gap(
            "goal_loop_empty",
            "human goal has not been set in this state",
            format!("octopus{state_args} goal set \"describe your goal\""),
        ));
    }
    if status.tentacles.is_empty() {
        gaps.push(product_gap(
            "no_installed_tentacles",
            "Needs cannot reach tool-side brains yet",
            format!("octopus{state_args} bootstrap"),
        ));
    }
    if !broken_manifests.is_empty() {
        gaps.push(product_gap(
            "broken_manifests",
            format!("missing entrypoints: {}", broken_manifests.join(", ")),
            "octopus manifests",
        ));
    }
    if !broken_installed_seed_sources.is_empty() {
        gaps.push(product_gap(
            "broken_installed_seed_sources",
            format!(
                "installed seed sources need repair: {}",
                broken_installed_seed_sources.join(", ")
            ),
            format!("octopus{state_args} beat 200"),
        ));
    }
    if !provider_ready {
        let next = if provider_configured {
            "octopus provider check"
        } else {
            "octopus provider save openai"
        };
        gaps.push(product_gap(
            "provider_feedback",
            "LLM-backed Goal chat, clean brain, tentacle planning, or evolution coverage is incomplete",
            next,
        ));
    }
    if !provider_matrix.passed {
        gaps.push(product_gap(
            "provider_matrix_record",
            "current-head OAuth, API-key, local model, and gateway provider evidence is incomplete",
            "octopus provider matrix; octopus provider matrix run; octopus provider matrix check",
        ));
    }
    if status.feed_trace_count == 0 {
        gaps.push(product_gap(
            "feed_trace_empty",
            "harness evolution has no Feed data to learn from",
            "octopus need observe .",
        ));
    }
    if status.check_history_count == 0 {
        gaps.push(product_gap(
            "check_history_empty",
            "harness beat cannot target failing runtime checks yet",
            "octopus check swe-agent",
        ));
    }
    if !profile_registry.ok {
        gaps.push(product_gap(
            "profile_registry_invalid",
            profile_registry
                .error
                .clone()
                .unwrap_or_else(|| "profile registry is not readable".to_string()),
            "octopus bootstrap",
        ));
    }
    if !boundary.ok {
        gaps.push(product_gap(
            "core_harness_boundary",
            boundary.warnings.join("; "),
            "octopus report",
        ));
    }
    if state.evolution_outcomes.is_empty() {
        gaps.push(product_gap(
            "evolution_scores_empty",
            "recommendations have not received outcome feedback",
            "octopus evolve score swe-agent 03-runtime-code partial \"reviewed\"",
        ));
    }
    if status.repair_outcome_count == 0 {
        gaps.push(product_gap(
            "repair_outcomes_empty",
            "harness repair sessions have no scored outcome memory yet",
            "octopus repair score <trace-index> satisfied \"repair improved harness\"",
        ));
    }
    if environment.recommended_profiles.is_empty() {
        gaps.push(product_gap(
            "environment_signal_sparse",
            "adapter selection has little local project evidence",
            "octopus env",
        ));
    }
    gaps.push(product_gap(
        "real_machine_gate",
        "0.1.0 and later tags need recorded real-machine testing",
        "update docs/real-machine-test.md before a 0.1.0 tag",
    ));
    gaps.sort_by(|left, right| left.id.cmp(&right.id));

    let mut next = gaps.iter().map(|gap| gap.next.clone()).collect::<Vec<_>>();
    next.push(status.next_action);
    next.extend(provider.next);
    next.sort();
    next.dedup();

    Ok(ProductReport {
        version: env!("CARGO_PKG_VERSION").to_string(),
        state_path: state_path.to_string_lossy().to_string(),
        state_exists: state_path.exists(),
        context: ProductContextPolicy {
            brain: "Goal + Mem + Need + Feed".to_string(),
            tentacle: "Need + Tool + Action + Tool + Action -> Feed".to_string(),
            feedback_loop: "Need -> Feed -> Feedback".to_string(),
        },
        field_pool,
        boundary,
        harness_learning: status.harness_learning,
        capabilities,
        gaps,
        next,
    })
}

fn product_field_pool_report(report: &FieldTrajectoryReport) -> ProductFieldPoolReport {
    let fields = report
        .fields
        .iter()
        .map(|field| field.field.clone())
        .collect::<Vec<_>>();
    let completed_fields = report
        .fields
        .iter()
        .filter(|field| {
            field.mini_task_count > 0 && field.satisfied_mini_task_count == field.mini_task_count
        })
        .count();
    ProductFieldPoolReport {
        policy: "eight peer field slots; workers are sampled execution slots".to_string(),
        field_count: report.field_count,
        fields,
        completed_fields,
        sampled_slot_field: report.sampled_slot_field.clone(),
        worker_slots: "worker count selects concurrent sampled slots; fields stay peer".to_string(),
        next: report.next.first().cloned().unwrap_or_default(),
    }
}

fn product_capability(
    id: impl Into<String>,
    status: impl Into<String>,
    evidence: impl Into<String>,
    command: Option<&str>,
) -> ProductCapability {
    ProductCapability {
        id: id.into(),
        status: status.into(),
        evidence: evidence.into(),
        command: command.map(str::to_string),
    }
}

fn product_gap(
    id: impl Into<String>,
    impact: impl Into<String>,
    next: impl Into<String>,
) -> ProductGap {
    ProductGap {
        id: id.into(),
        impact: impact.into(),
        next: next.into(),
    }
}

fn preflight_report(
    state: &HarnessState,
    state_path: &Path,
    live: bool,
) -> Result<PreflightReport, String> {
    let product = product_report(state, state_path)?;
    let doctor = doctor_report(state, state_path.to_path_buf())?;
    let provider = provider_status_report();
    let provider_matrix = check_provider_matrix_record(Path::new(DEFAULT_PROVIDER_MATRIX_PATH))?;
    let current_head = git_short_head();
    let benchmark_record = check_benchmark_record(
        Path::new(DEFAULT_BENCHMARK_RECORD_PATH),
        current_head.clone(),
    )?;
    let status = &doctor.status;
    let real_machine_doc = repo_root().join("docs/real-machine-test.md");
    let real_machine_log = fs::read_to_string(&real_machine_doc).unwrap_or_default();
    let real_machine_record =
        real_machine_record_status(current_head.as_deref(), &real_machine_log);
    let seed_tentacles = bootstrap_seed_tentacles();
    let missing_seed_tentacles = seed_tentacles
        .iter()
        .filter(|id| {
            !state
                .installed_tentacles
                .iter()
                .any(|tentacle| tentacle.id == **id)
        })
        .map(|id| (*id).to_string())
        .collect::<Vec<_>>();
    let provider_layers_ready = provider_coverage_ready(&provider);
    let github_grant = state.active_grant("github", "dangoZhang/Octopus").is_some();
    let gh_ready = command_ready("gh");
    let docs_ready = repo_root().join("README.md").exists()
        && repo_root().join("docs/index.html").exists()
        && repo_root().join("docs/app.html").exists()
        && repo_root().join("docs/pet.html").exists();
    let scored_feed_traces = state
        .feed_traces
        .iter()
        .filter(|trace| trace.metadata.contains_key("feedback_status"))
        .count();
    let feedback_ready = scored_feed_traces > 0;
    let mut live_provider = None;
    let mut live_provider_error = None;
    if live {
        match provider_check_report(
            &doctor.llm.config_prefix,
            "Reply with 'octopus provider live'.",
        ) {
            Ok(report) => live_provider = Some(report),
            Err(error) => live_provider_error = Some(error),
        }
    }

    let mut checks = vec![
        preflight_check(
            "state",
            state_path.exists(),
            true,
            format!(
                "{} ({})",
                state_path.to_string_lossy(),
                if state_path.exists() {
                    "exists"
                } else {
                    "missing"
                }
            ),
            "octopus bootstrap",
        ),
        preflight_check(
            "seed_tentacles",
            missing_seed_tentacles.is_empty(),
            true,
            if missing_seed_tentacles.is_empty() {
                format!("{} seed tentacles installed", seed_tentacles.len())
            } else {
                format!("missing {}", missing_seed_tentacles.join(", "))
            },
            "octopus bootstrap",
        ),
        preflight_check(
            "manifest_integrity",
            doctor.broken_manifests.is_empty() && doctor.manifest_count > 0,
            true,
            if doctor.broken_manifests.is_empty() {
                format!("{} manifests clean", doctor.manifest_count)
            } else {
                doctor.broken_manifests.join("; ")
            },
            "octopus manifests",
        ),
        preflight_check(
            "profile_registry",
            doctor.profile_registry.ok,
            true,
            format!(
                "source={}, path={}, profiles={}, error={}",
                doctor.profile_registry.source,
                doctor.profile_registry.path,
                doctor.profile_registry.profile_count,
                doctor.profile_registry.error.as_deref().unwrap_or("none")
            ),
            "octopus bootstrap",
        ),
        preflight_check(
            "clean_brain_boundary",
            product.context.brain == CLEAN_BRAIN_CONTEXT_POLICY
                && product.context.tentacle == TENTACLE_CONTEXT_POLICY,
            true,
            format!(
                "brain={}, tentacle={}",
                product.context.brain, product.context.tentacle
            ),
            "octopus context observe .",
        ),
        preflight_check(
            "core_harness_boundary",
            product.boundary.ok,
            true,
            format!(
                "stable_rust={}, product_app={}, editable_harness={}, warnings={}",
                product.boundary.stable_rust.len(),
                product.boundary.product_app.len(),
                product.boundary.editable_harness.len(),
                if product.boundary.warnings.is_empty() {
                    "none".to_string()
                } else {
                    product.boundary.warnings.join("; ")
                }
            ),
            "octopus report",
        ),
        preflight_check(
            "field_parallel_pool",
            product.field_pool.field_count >= 8,
            true,
            format!(
                "{} peer slots, completed={}, sampled_slot={}, workers={}",
                product.field_pool.field_count,
                product.field_pool.completed_fields,
                option_or_none(&product.field_pool.sampled_slot_field),
                product.field_pool.worker_slots
            ),
            "octopus fields summary",
        ),
        app_bridge::goal_surface_preflight_check(state_path),
        app_bridge::local_app_run_status_check(state_path, current_head.as_deref()),
        preflight_check(
            "docs_and_pet",
            docs_ready,
            true,
            "README, docs homepage, app, and pixel pet files",
            "octopus start",
        ),
        download_artifacts_preflight_check(),
        preflight_check(
            "provider_layers",
            provider_layers_ready,
            true,
            provider
                .coverage
                .iter()
                .map(|coverage| {
                    format!(
                        "{} ready={} prefixes={} blockers={}",
                        coverage.id,
                        coverage.ready,
                        join_or_none(&coverage.prefixes),
                        join_or_none(&coverage.blockers)
                    )
                })
                .collect::<Vec<_>>()
                .join("; "),
            "octopus provider save openai; source .octopus/llm.env; octopus provider status",
        ),
        preflight_check(
            "provider_matrix_record",
            provider_matrix.passed,
            true,
            provider_matrix_check_evidence(&provider_matrix),
            "octopus provider matrix; octopus provider matrix run; octopus provider matrix check",
        ),
        preflight_check(
            "benchmark_evidence",
            benchmark_record.passed,
            true,
            benchmark_record_evidence(&benchmark_record),
            "octopus benchmark record; run cases; octopus benchmark check",
        ),
        preflight_status_check(
            "live_provider",
            if live {
                if live_provider.is_some() {
                    "pass"
                } else {
                    "fail"
                }
            } else {
                "skipped"
            },
            true,
            live_provider
                .as_ref()
                .map(|report| report.content.clone())
                .or(live_provider_error)
                .unwrap_or_else(|| "not run; pass --live to call the provider".to_string()),
            format!(
                "octopus --state {} preflight --live",
                shell_arg(&state_path.to_string_lossy())
            ),
        ),
        preflight_check(
            "feedback_data",
            feedback_ready,
            true,
            format!(
                "scored_traces={}, traces={}, checks={}, evolution_scores={}",
                scored_feed_traces,
                status.feed_trace_count,
                status.check_history_count,
                state.evolution_outcomes.len()
            ),
            format!(
                "octopus --state {} first-run \"collect local feedback evidence\"",
                shell_arg(&state_path.to_string_lossy())
            ),
        ),
        preflight_check(
            "github_pr_path",
            github_grant && gh_ready,
            true,
            format!("gh_cli={}, oauth_grant={}", gh_ready, github_grant),
            "gh auth login; octopus oauth github dangoZhang/Octopus repo workflow",
        ),
        preflight_check(
            "real_machine_record",
            real_machine_record.passed,
            true,
            real_machine_record.evidence,
            "octopus preflight record",
        ),
        preflight_check(
            "desktop_adapters",
            state
                .installed_tentacles
                .iter()
                .any(|tentacle| tentacle.id == "computer-use-agent"),
            false,
            "computer-use-agent installed for desktop/browser probes",
            "octopus install computer-use-agent",
        ),
        preflight_check(
            "harness_repair",
            state
                .installed_tentacles
                .iter()
                .any(|tentacle| tentacle.id == "harness-repair-agent"),
            false,
            "harness-repair-agent installed for tool-side diagnosis",
            "octopus install harness-repair-agent",
        ),
    ];
    checks.sort_by(|left, right| left.id.cmp(&right.id));
    let release_ready = checks
        .iter()
        .filter(|check| check.required)
        .all(|check| check.status == "pass");
    let summary = preflight_summary(&checks);
    let mut next = checks
        .iter()
        .filter(|check| check.status != "pass")
        .map(|check| check.next.clone())
        .collect::<Vec<_>>();
    next.push("octopus preflight script".to_string());
    next.push("octopus preflight record".to_string());
    next.push("octopus report".to_string());
    next.sort();
    next.dedup();

    Ok(PreflightReport {
        version: env!("CARGO_PKG_VERSION").to_string(),
        target: "0.1.0".to_string(),
        state_path: state_path.to_string_lossy().to_string(),
        live,
        release_ready,
        summary,
        current_head,
        checks,
        live_provider,
        next,
    })
}

fn preflight_summary(checks: &[PreflightCheck]) -> PreflightSummary {
    let required_total = checks.iter().filter(|check| check.required).count();
    let required_passed = checks
        .iter()
        .filter(|check| check.required && check.status == "pass")
        .count();
    let optional_total = checks.iter().filter(|check| !check.required).count();
    let optional_passed = checks
        .iter()
        .filter(|check| !check.required && check.status == "pass")
        .count();
    let blockers = checks
        .iter()
        .filter(|check| check.required && check.status != "pass")
        .map(|check| PreflightBlocker {
            id: check.id.clone(),
            status: check.status.clone(),
            evidence: check.evidence.clone(),
            next: check.next.clone(),
        })
        .collect::<Vec<_>>();
    let next_steps = blockers
        .iter()
        .map(|blocker| blocker.next.clone())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect();
    PreflightSummary {
        required_passed,
        required_total,
        optional_passed,
        optional_total,
        blockers,
        next_steps,
    }
}

fn write_preflight_script(
    state_path: &Path,
    output_path: &Path,
) -> Result<PreflightScriptReport, String> {
    if let Some(parent) = output_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
    {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let commands = preflight_script_commands();
    let state_default = shell_arg(&state_path.to_string_lossy());
    let content = format!(
        r#"#!/bin/sh
set -eu

STATE=${{OCTOPUS_PREFLIGHT_STATE:-{state_default}}}
ROOT=${{OCTOPUS_PREFLIGHT_ROOT:-$(pwd)}}

cd "$ROOT"

{commands}

if [ "${{OCTOPUS_PREFLIGHT_LIVE:-0}}" = "1" ]; then
  octopus provider status
  octopus provider check "${{OCTOPUS_LLM_PREFIX:-OCTOPUS_LLM}}"
  octopus --state "$STATE" preflight --live
else
  octopus --state "$STATE" preflight
fi

if [ "${{OCTOPUS_PREFLIGHT_PR_DRY_RUN:-0}}" = "1" ]; then
  gh auth status
  octopus --state "$STATE" self-iterate dangoZhang/Octopus
  OCTOPUS_PR_DRY_RUN=1 octopus --state "$STATE" self-iterate pr dangoZhang/Octopus "preflight dry run"
fi
"#,
        commands = commands.join("\n")
    );
    fs::write(output_path, content).map_err(|error| error.to_string())?;
    Ok(PreflightScriptReport {
        path: output_path.to_string_lossy().to_string(),
        state_path: state_path.to_string_lossy().to_string(),
        commands,
        next: vec![
            format!("sh {}", shell_arg(&output_path.to_string_lossy())),
            format!(
                "OCTOPUS_PREFLIGHT_LIVE=1 sh {}",
                shell_arg(&output_path.to_string_lossy())
            ),
            format!(
                "OCTOPUS_PREFLIGHT_PR_DRY_RUN=1 sh {}",
                shell_arg(&output_path.to_string_lossy())
            ),
        ],
    })
}

fn write_preflight_record(
    state_path: &Path,
    output_path: &Path,
) -> Result<PreflightRecordReport, String> {
    if let Some(parent) = output_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
    {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let current_head = git_short_head();
    let version = env!("CARGO_PKG_VERSION").to_string();
    let commands = preflight_record_commands(state_path, current_head.as_deref(), shell_arg);
    let head_for_record = current_head.as_deref().unwrap_or("unknown");
    let content = format!(
        r#"# Real-Machine Record

Append the completed result to `docs/real-machine-test.md` after the run.

## Machine

- Date:
- Tester:
- Machine:
- OS:
- Shell:
- Rust:
- Python:
- Git commit: `{head}`
- Package version: `{version}`
- State: `{state}`

## Commands

```bash
{commands}
```

## Results

- Install and doctor:
- Download artifacts:
- Core loop:
- Product bridge:
- Field pool:
- Start/app:
- Live provider:
- Benchmark evidence:
- PR dry run:

## Decision

- Pass or fail:
- Follow-up:
"#,
        head = head_for_record,
        version = version,
        state = state_path.to_string_lossy(),
        commands = commands.join("\n")
    );
    fs::write(output_path, content).map_err(|error| error.to_string())?;
    Ok(PreflightRecordReport {
        path: output_path.to_string_lossy().to_string(),
        state_path: state_path.to_string_lossy().to_string(),
        version,
        current_head,
        commands,
        next: vec![
            format!("review {}", shell_arg(&output_path.to_string_lossy())),
            "run the commands on a clean real machine".to_string(),
            "append the completed result to docs/real-machine-test.md".to_string(),
            "octopus preflight".to_string(),
        ],
    })
}

fn check_preflight_record(path: &Path) -> Result<PreflightRecordCheckReport, String> {
    let current_head = git_short_head();
    let content = fs::read_to_string(path).unwrap_or_default();
    let file_exists = path.exists();
    let machine_fields = ["Date", "Tester", "Machine", "OS", "Shell", "Rust", "Python"];
    let missing_machine = machine_fields
        .iter()
        .filter(|field| record_field_value(&content, field).is_none())
        .map(|field| (*field).to_string())
        .collect::<Vec<_>>();
    let result_fields: &[&[&str]] = &[
        &["Install and doctor"],
        &["Download artifacts"],
        &["Core loop"],
        &["Product bridge"],
        &["Field pool"],
        &["Start/app", "Bridge/app"],
        &["Live provider"],
        &["Benchmark evidence"],
        &["PR dry run"],
    ];
    let missing_results = result_fields
        .iter()
        .filter(|fields| {
            fields
                .iter()
                .all(|field| record_field_value(&content, field).is_none())
        })
        .map(|fields| fields[0].to_string())
        .collect::<Vec<_>>();
    let pass_decision_value = record_field_value(&content, "Pass or fail");
    let pass_decision = pass_decision_value
        .as_deref()
        .is_some_and(record_pass_decision_ready);
    let head_ready = current_head
        .as_ref()
        .is_some_and(|head| content.contains(&format!("`{head}`")) || content.contains(head));
    let mut checks = vec![
        preflight_check(
            "record_file",
            file_exists,
            true,
            path.to_string_lossy(),
            "octopus preflight record",
        ),
        preflight_check(
            "current_head",
            head_ready,
            true,
            current_head
                .as_ref()
                .map(|head| format!("record must include current head {head}"))
                .unwrap_or_else(|| "git head unavailable".to_string()),
            "rerun octopus preflight record on the target head",
        ),
        preflight_check(
            "machine_fields",
            missing_machine.is_empty(),
            true,
            if missing_machine.is_empty() {
                "machine fields filled".to_string()
            } else {
                format!("missing {}", missing_machine.join(", "))
            },
            "fill Date, Tester, Machine, OS, Shell, Rust, and Python",
        ),
        preflight_check(
            "result_fields",
            missing_results.is_empty(),
            true,
            if missing_results.is_empty() {
                "result fields filled".to_string()
            } else {
                format!("missing {}", missing_results.join(", "))
            },
            "fill Install, Download artifacts, Core loop, Product bridge, Field pool, Start/app, Live provider, Benchmark evidence, and PR dry run results",
        ),
        preflight_check(
            "pass_decision",
            pass_decision,
            true,
            pass_decision_value.unwrap_or_else(|| "missing pass/fail decision".to_string()),
            "write Pass or fail: pass after real-machine checks pass",
        ),
        preflight_check(
            "command_coverage",
            content.contains("first-run")
                && content.contains("download")
                && content.contains("download.json")
                && content.contains("install.sh")
                && content.contains("bridge_goal_surface")
                && content.contains("provider matrix")
                && content.contains("provider matrix run")
                && content.contains("provider matrix check")
                && content.contains("fields summary")
                && content.contains("benchmark record")
                && content.contains("benchmark check")
                && content.contains("preflight --live")
                && content.contains("start --check")
                && content.contains("self-iterate pr"),
            true,
            "record should include first-run, download artifacts, bridge_goal_surface, provider matrix run/check, field pool summary, live provider, benchmark record/check, start --check, and PR dry-run commands",
            "regenerate with octopus preflight record",
        ),
    ];
    checks.sort_by(|left, right| left.id.cmp(&right.id));
    let passed = checks
        .iter()
        .filter(|check| check.required)
        .all(|check| check.status == "pass");
    let next = if passed {
        vec![
            format!(
                "octopus preflight record append {}",
                shell_arg(&path.to_string_lossy())
            ),
            "octopus preflight".to_string(),
        ]
    } else {
        checks
            .iter()
            .filter(|check| check.status != "pass")
            .map(|check| check.next.clone())
            .collect::<Vec<_>>()
    };
    Ok(PreflightRecordCheckReport {
        path: path.to_string_lossy().to_string(),
        current_head,
        passed,
        checks,
        next,
    })
}

fn append_preflight_record(
    record_path: &Path,
    log_path: &Path,
) -> Result<PreflightRecordAppendReport, String> {
    let check = check_preflight_record(record_path)?;
    if !check.passed {
        let missing = check
            .checks
            .iter()
            .filter(|item| item.status != "pass")
            .map(|item| item.id.as_str())
            .collect::<Vec<_>>()
            .join(", ");
        return Err(format!(
            "preflight record is not ready: {}; run octopus preflight record check",
            if missing.is_empty() {
                "unknown checks failed".to_string()
            } else {
                missing
            }
        ));
    }
    let record = fs::read_to_string(record_path).map_err(|error| error.to_string())?;
    let record_body = record.trim();
    if record_body.is_empty() {
        return Err("preflight record is empty".to_string());
    }
    if let Some(parent) = log_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
    {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let mut log = fs::read_to_string(log_path).unwrap_or_else(|_| {
        "# Real-Machine Test Gate\n\nRequired before `0.1.0` and every later version tag.\n"
            .to_string()
    });
    let already_present = log.contains(record_body);
    let mut appended = false;
    if !already_present {
        if !log.ends_with('\n') {
            log.push('\n');
        }
        log.push_str("\n---\n\n## Appended Real-Machine Record\n\n");
        log.push_str(record_body);
        log.push('\n');
        fs::write(log_path, &log).map_err(|error| error.to_string())?;
        appended = true;
    }
    Ok(PreflightRecordAppendReport {
        record_path: record_path.to_string_lossy().to_string(),
        log_path: log_path.to_string_lossy().to_string(),
        current_head: check.current_head.clone(),
        appended,
        already_present,
        bytes: record_body.len(),
        check,
        next: vec![
            "octopus preflight".to_string(),
            format!("git add {}", shell_arg(&log_path.to_string_lossy())),
            "git commit -m \"Record real-machine preflight\"".to_string(),
        ],
    })
}

fn git_short_head() -> Option<String> {
    git_short_rev("HEAD")
}

fn real_machine_record_status(current_head: Option<&str>, log: &str) -> RealMachineRecordStatus {
    let parent_head = git_short_rev("HEAD^");
    let changed_files = git_changed_files("HEAD^", "HEAD");
    real_machine_record_status_from_parts(
        current_head,
        parent_head.as_deref(),
        changed_files.as_deref(),
        log,
    )
}

fn git_short_rev(rev: &str) -> Option<String> {
    let output = Command::new("git")
        .args(["rev-parse", "--short", rev])
        .output()
        .ok()?;
    output
        .status
        .success()
        .then(|| String::from_utf8_lossy(&output.stdout).trim().to_string())
}

fn git_changed_files(base: &str, head: &str) -> Option<Vec<String>> {
    let output = Command::new("git")
        .args(["diff", "--name-only", base, head])
        .output()
        .ok()?;
    output.status.success().then(|| {
        String::from_utf8_lossy(&output.stdout)
            .lines()
            .map(str::trim)
            .filter(|line| !line.is_empty())
            .map(str::to_string)
            .collect()
    })
}

