            println!(
                "Harness学习: {}",
                harness_learning_line(&report.harness_learning)
            );
            println!(
                "稳定 Rust: {}",
                join_or_none(
                    &report
                        .boundary
                        .stable_rust
                        .iter()
                        .map(|item| format!("{}={}", item.kind, item.path))
                        .collect::<Vec<_>>()
                )
            );
            println!(
                "可变 harness: {}",
                join_or_none(
                    &report
                        .boundary
                        .editable_harness
                        .iter()
                        .map(|item| format!("{}={}", item.kind, item.path))
                        .collect::<Vec<_>>()
                )
            );
            if !report.boundary.warnings.is_empty() {
                println!("边界警告: {}", join_or_none(&report.boundary.warnings));
            }
