    #[cfg(unix)]
    #[test]
    fn cli_brain_clarify_live_uses_slot_without_feed() {
        use std::os::unix::fs::PermissionsExt;

        let _env = env_guard();
        let dir =
            std::env::temp_dir().join(format!("octopus-brain-clarify-live-{}", std::process::id()));
        let state_path = dir.join("state.json");
        let state = state_path.to_string_lossy().to_string();
        let _ = fs::remove_dir_all(&dir);
        fs::create_dir_all(&dir).unwrap();
        let curl = dir.join("clarify-curl.sh");
        fs::write(
            &curl,
            r#"#!/bin/sh
printf '%s' '{"choices":[{"message":{"content":"{\"summary\":\"clarify slot reply\",\"observations\":[\"slot observation\"],\"questions\":[\"slot question\"],\"options\":[\"slot option\"],\"risks\":[\"slot risk\"],\"needs\":[{\"kind\":\"verify\",\"query\":\"clarify-slot cognitive need\"}]}"}}]}'
"#,
        )
        .unwrap();
        let mut permissions = fs::metadata(&curl).unwrap().permissions();
        permissions.set_mode(0o755);
        fs::set_permissions(&curl, permissions).unwrap();

        let old_brain = std::env::var("OCTOPUS_BRAIN_LLM").ok();
        let old_brain_prefix = std::env::var("OCTOPUS_BRAIN_LLM_PREFIX").ok();
        let old_clarify_prefix = std::env::var("OCTOPUS_BRAIN_CLARIFY_LLM_PREFIX").ok();
        let old_model = std::env::var("OCTOPUS_SLOT_CLARIFY_MODEL").ok();
        let old_base_url = std::env::var("OCTOPUS_SLOT_CLARIFY_BASE_URL").ok();
        let old_api_key = std::env::var("OCTOPUS_SLOT_CLARIFY_API_KEY").ok();
        let old_curl = std::env::var("OCTOPUS_SLOT_CLARIFY_CURL").ok();
        std::env::set_var("OCTOPUS_BRAIN_LLM", "1");
        std::env::set_var("OCTOPUS_BRAIN_LLM_PREFIX", "OCTOPUS_UNUSED_BRAIN");
        std::env::set_var("OCTOPUS_BRAIN_CLARIFY_LLM_PREFIX", "OCTOPUS_SLOT_CLARIFY");
        std::env::set_var("OCTOPUS_SLOT_CLARIFY_MODEL", "clarify-model");
        std::env::set_var(
            "OCTOPUS_SLOT_CLARIFY_BASE_URL",
            "https://clarify.example/v1",
        );
        std::env::remove_var("OCTOPUS_SLOT_CLARIFY_API_KEY");
        std::env::set_var(
            "OCTOPUS_SLOT_CLARIFY_CURL",
            curl.to_string_lossy().to_string(),
        );

        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "brain".to_string(),
            "--clarify".to_string(),
            "--live".to_string(),
            "--save".to_string(),
            "clarify".to_string(),
            "goal".to_string(),
        ])
        .unwrap();

        restore_env("OCTOPUS_BRAIN_LLM", old_brain);
        restore_env("OCTOPUS_BRAIN_LLM_PREFIX", old_brain_prefix);
        restore_env("OCTOPUS_BRAIN_CLARIFY_LLM_PREFIX", old_clarify_prefix);
        restore_env("OCTOPUS_SLOT_CLARIFY_MODEL", old_model);
        restore_env("OCTOPUS_SLOT_CLARIFY_BASE_URL", old_base_url);
        restore_env("OCTOPUS_SLOT_CLARIFY_API_KEY", old_api_key);
        restore_env("OCTOPUS_SLOT_CLARIFY_CURL", old_curl);

        let restored = HarnessState::load(&state_path).unwrap();
        assert_eq!(restored.pending_need_queue_count(), 1);
        assert!(restored.feed_traces.is_empty());
        assert!(restored.routes.scores.is_empty());
        let content = fs::read_to_string(&state_path).unwrap();
        assert!(content.contains("clarify slot reply"));
        assert!(content.contains("clarify-slot cognitive need"));
        let _ = fs::remove_dir_all(dir);
    }

