    #[cfg(unix)]
    #[test]
    fn cli_repair_report_extracts_provider_patch_draft() {
        use std::os::unix::fs::PermissionsExt;

        let _env = env_guard();
        let _cwd = CwdGuard::new();
        let dir = std::env::temp_dir().join(format!(
            "octopus-repair-provider-patch-{}",
            std::process::id()
        ));
        let _ = fs::remove_dir_all(&dir);
        fs::create_dir_all(&dir).unwrap();
        std::env::set_current_dir(&dir).unwrap();
        fs::create_dir_all(dir.join("tentacles/harness-repair-agent/tools")).unwrap();
        fs::write(
            dir.join("tentacles/harness-repair-agent/tools/repair_session.sh"),
            "#!/usr/bin/env bash\nset -euo pipefail\n",
        )
        .unwrap();
        let curl = dir.join("fake-repair-curl.sh");
        fs::write(
            &curl,
            r#"#!/bin/sh
cat <<'JSON'
{"choices":[{"message":{"content":"diagnosis\n```diff\ndiff --git a/tentacles/harness-repair-agent/tools/repair_session.sh b/tentacles/harness-repair-agent/tools/repair_session.sh\n--- a/tentacles/harness-repair-agent/tools/repair_session.sh\n+++ b/tentacles/harness-repair-agent/tools/repair_session.sh\n@@ -1,2 +1,3 @@\n #!/usr/bin/env bash\n+# provider repair patch\n set -euo pipefail\n```\nchecks: cargo test repair"}}]}
JSON
"#,
        )
        .unwrap();
        let mut permissions = fs::metadata(&curl).unwrap().permissions();
        permissions.set_mode(0o755);
        fs::set_permissions(&curl, permissions).unwrap();
        let state_path = dir.join(".octopus/state.json");
        let state = state_path.to_string_lossy().to_string();

        let old_repair = std::env::var("OCTOPUS_REPAIR_LLM").ok();
        let old_prefix = std::env::var("OCTOPUS_REPAIR_LLM_PREFIX").ok();
        let old_model = std::env::var("OCTOPUS_REPAIR_TEST_MODEL").ok();
        let old_base_url = std::env::var("OCTOPUS_REPAIR_TEST_BASE_URL").ok();
        let old_curl = std::env::var("OCTOPUS_REPAIR_TEST_CURL").ok();
        std::env::set_var("OCTOPUS_REPAIR_LLM", "1");
        std::env::set_var("OCTOPUS_REPAIR_LLM_PREFIX", "OCTOPUS_REPAIR_TEST");
        std::env::set_var("OCTOPUS_REPAIR_TEST_MODEL", "test-model");
        std::env::set_var("OCTOPUS_REPAIR_TEST_BASE_URL", "https://llm.example/v1");
        std::env::set_var(
            "OCTOPUS_REPAIR_TEST_CURL",
            curl.to_string_lossy().to_string(),
        );

        run(vec![
            "--state".to_string(),
            state.clone(),
            "install".to_string(),
            "harness-repair-agent".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state,
            "need".to_string(),
            "execute".to_string(),
            dir.to_string_lossy().to_string(),
        ])
        .unwrap();

        restore_env("OCTOPUS_REPAIR_LLM", old_repair);
        restore_env("OCTOPUS_REPAIR_LLM_PREFIX", old_prefix);
        restore_env("OCTOPUS_REPAIR_TEST_MODEL", old_model);
        restore_env("OCTOPUS_REPAIR_TEST_BASE_URL", old_base_url);
        restore_env("OCTOPUS_REPAIR_TEST_CURL", old_curl);

        let mut restored = HarnessState::load(&state_path).unwrap();
        let report = repair_report(&state_path, &mut restored, ".".to_string()).unwrap();
        let plan = report.repair_plan.expect("repair plan report");

        assert_eq!(plan.draft_status, "generated");
        assert_eq!(plan.draft_model, "test-model");
        assert!(plan
            .repair_draft_strategy
            .ends_with("REPAIR_DRAFT_STRATEGY.md"));
        assert_eq!(
            plan.repair_draft_strategy_status,
            "review_generated_repair_draft"
        );
        assert_eq!(plan.repair_patch_draft_status, "patch_attached");
        assert_eq!(plan.repair_patch_draft_has_patch, "true");
        assert_eq!(plan.repair_patch_review_status, "check_passed");
        assert_eq!(plan.repair_patch_review_check_status, "passed");
        assert_eq!(plan.repair_patch_review_has_patch, "true");
        assert!(plan.repair_patch_review_summary.contains("applies cleanly"));
        assert_eq!(plan.repair_patch_apply_status, "ready_for_authorized_apply");
        assert_eq!(plan.repair_patch_apply_applied, "false");
        assert_eq!(plan.repair_patch_apply_authorized, "false");
        assert_eq!(
            plan.repair_patch_apply_required_grant,
            "octopus:evolve:harness-repair-agent"
        );
        assert_eq!(plan.repair_patch_verify_status, "waiting_for_patch_apply");
        assert_eq!(plan.repair_patch_verify_passed, "false");
        assert!(plan
            .repair_patch_verify_command
            .contains("harness-repair-agent"));
        assert!(plan
            .repair_patch_learning
            .ends_with("REPAIR_PATCH_LEARNING.md"));
        assert!(plan
            .repair_patch_learning_effectiveness
            .ends_with("REPAIR_PATCH_LEARNING_EFFECTIVENESS.md"));
        assert!(plan
            .repair_patch_strategy
            .ends_with("REPAIR_PATCH_STRATEGY.md"));
        assert!(plan
            .repair_patch_strategy_effectiveness
            .ends_with("REPAIR_PATCH_STRATEGY_EFFECTIVENESS.md"));
        assert_eq!(plan.repair_patch_strategy_status, "review_checked_patch");
        assert!(plan
            .repair_patch_strategy_next_need_query
            .contains("review checked repair patch"));
        assert_eq!(
            plan.repair_patch_learning_status,
            "collect_verified_patch_outcomes"
        );
        let patch_draft_json = fs::read_to_string(&plan.repair_patch_draft_json).unwrap();
        assert!(patch_draft_json
            .contains("\"schema_version\": \"octopus-harness-repair-patch-draft-v1\""));
        assert!(patch_draft_json.contains("provider repair patch"));
        assert!(patch_draft_json.contains("diff --git"));
        let patch_review_json = fs::read_to_string(&plan.repair_patch_review_json).unwrap();
        assert!(patch_review_json
            .contains("\"schema_version\": \"octopus-harness-repair-patch-review-v1\""));
        assert!(patch_review_json.contains("\"status\": \"check_passed\""));
        assert!(patch_review_json.contains("git apply --check"));
        let patch_apply_json = fs::read_to_string(&plan.repair_patch_apply_json).unwrap();
        assert!(patch_apply_json
            .contains("\"schema_version\": \"octopus-harness-repair-patch-apply-v1\""));
        assert!(patch_apply_json.contains("\"status\": \"ready_for_authorized_apply\""));
        assert!(patch_apply_json.contains("octopus repair apply"));
        let patch_verify_json = fs::read_to_string(&plan.repair_patch_verify_json).unwrap();
        assert!(patch_verify_json
            .contains("\"schema_version\": \"octopus-harness-repair-patch-verify-v1\""));
        assert!(patch_verify_json.contains("\"status\": \"waiting_for_patch_apply\""));
        let patch_learning_json = fs::read_to_string(&plan.repair_patch_learning_json).unwrap();
        assert!(patch_learning_json
            .contains("\"schema_version\": \"octopus-harness-repair-patch-learning-v1\""));
        let patch_learning_effectiveness_json =
            fs::read_to_string(&plan.repair_patch_learning_effectiveness_json).unwrap();
        assert!(patch_learning_effectiveness_json.contains(
            "\"schema_version\": \"octopus-harness-repair-patch-learning-effectiveness-v1\""
        ));
        let draft_strategy_json = fs::read_to_string(&plan.repair_draft_strategy_json).unwrap();
        assert!(draft_strategy_json
            .contains("\"schema_version\": \"octopus-harness-repair-draft-strategy-v1\""));
        assert!(draft_strategy_json.contains("\"status\": \"review_generated_repair_draft\""));
        let patch_strategy_json = fs::read_to_string(&plan.repair_patch_strategy_json).unwrap();
        assert!(patch_strategy_json
            .contains("\"schema_version\": \"octopus-harness-repair-patch-strategy-v1\""));
        assert!(patch_strategy_json.contains("\"status\": \"review_checked_patch\""));
        let patch_strategy_effectiveness_json =
            fs::read_to_string(&plan.repair_patch_strategy_effectiveness_json).unwrap();
        assert!(patch_strategy_effectiveness_json.contains(
            "\"schema_version\": \"octopus-harness-repair-patch-strategy-effectiveness-v1\""
        ));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("REPAIR_DRAFT_STRATEGY.md")));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("REPAIR_PATCH_DRAFT.md")));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("REPAIR_PATCH_REVIEW.md")));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("REPAIR_PATCH_APPLY.md")));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("REPAIR_PATCH_VERIFY.md")));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("REPAIR_PATCH_LEARNING.md")));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("REPAIR_PATCH_STRATEGY.md")));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("REPAIR_PATCH_STRATEGY_EFFECTIVENESS.md")));
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("octopus repair apply")));

        std::env::set_current_dir(&_cwd.original).unwrap();
        let _ = fs::remove_dir_all(dir);
    }

    #[cfg(unix)]
    #[test]
    fn cli_repair_apply_requires_grant_and_applies_reviewed_patch() {
        use std::os::unix::fs::PermissionsExt;

        let _env = env_guard();
        let _cwd = CwdGuard::new();
        let dir =
            std::env::temp_dir().join(format!("octopus-repair-patch-apply-{}", std::process::id()));
        let _ = fs::remove_dir_all(&dir);
        fs::create_dir_all(&dir).unwrap();
        std::env::set_current_dir(&dir).unwrap();
        let target = dir.join("tentacles/harness-repair-agent/tools/repair_session.sh");
        fs::create_dir_all(target.parent().unwrap()).unwrap();
        fs::write(&target, "#!/usr/bin/env bash\nset -euo pipefail\n").unwrap();
        let curl = dir.join("fake-repair-curl.sh");
        fs::write(
            &curl,
            r#"#!/bin/sh
cat <<'JSON'
{"choices":[{"message":{"content":"diagnosis\n```diff\ndiff --git a/tentacles/harness-repair-agent/tools/repair_session.sh b/tentacles/harness-repair-agent/tools/repair_session.sh\n--- a/tentacles/harness-repair-agent/tools/repair_session.sh\n+++ b/tentacles/harness-repair-agent/tools/repair_session.sh\n@@ -1,2 +1,3 @@\n #!/usr/bin/env bash\n+# provider repair patch\n set -euo pipefail\n```\nchecks: cargo test repair"}}]}
JSON
"#,
        )
        .unwrap();
        let mut permissions = fs::metadata(&curl).unwrap().permissions();
        permissions.set_mode(0o755);
        fs::set_permissions(&curl, permissions).unwrap();
        let state_path = dir.join(".octopus/state.json");
        let state = state_path.to_string_lossy().to_string();

        let old_repair = std::env::var("OCTOPUS_REPAIR_LLM").ok();
        let old_prefix = std::env::var("OCTOPUS_REPAIR_LLM_PREFIX").ok();
        let old_model = std::env::var("OCTOPUS_REPAIR_TEST_MODEL").ok();
        let old_base_url = std::env::var("OCTOPUS_REPAIR_TEST_BASE_URL").ok();
        let old_curl = std::env::var("OCTOPUS_REPAIR_TEST_CURL").ok();
        std::env::set_var("OCTOPUS_REPAIR_LLM", "1");
        std::env::set_var("OCTOPUS_REPAIR_LLM_PREFIX", "OCTOPUS_REPAIR_TEST");
        std::env::set_var("OCTOPUS_REPAIR_TEST_MODEL", "test-model");
        std::env::set_var("OCTOPUS_REPAIR_TEST_BASE_URL", "https://llm.example/v1");
        std::env::set_var(
            "OCTOPUS_REPAIR_TEST_CURL",
            curl.to_string_lossy().to_string(),
        );

        run(vec![
            "--state".to_string(),
            state.clone(),
            "install".to_string(),
            "harness-repair-agent".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "need".to_string(),
            "execute".to_string(),
            dir.to_string_lossy().to_string(),
        ])
        .unwrap();

        restore_env("OCTOPUS_REPAIR_LLM", old_repair);
        restore_env("OCTOPUS_REPAIR_LLM_PREFIX", old_prefix);
        restore_env("OCTOPUS_REPAIR_TEST_MODEL", old_model);
        restore_env("OCTOPUS_REPAIR_TEST_BASE_URL", old_base_url);
        restore_env("OCTOPUS_REPAIR_TEST_CURL", old_curl);

        let restored = HarnessState::load(&state_path).unwrap();
        let unauthorized =
            repair_patch_apply_report(&state_path, &restored, ".".to_string()).unwrap();
        assert_eq!(unauthorized.status, "needs_authorization");
        assert!(!unauthorized.applied);
        assert!(!unauthorized.authorized);
        assert!(unauthorized
            .grant_command
            .contains("evolve:harness-repair-agent"));
        assert!(!fs::read_to_string(&target)
            .unwrap()
            .contains("provider repair patch"));
        let unauthorized_json = fs::read_to_string(&unauthorized.apply).unwrap();
        assert!(unauthorized_json.contains("\"status\": \"needs_authorization\""));
        assert!(unauthorized_json.contains("\"authorized\": false"));

        run(vec![
            "--state".to_string(),
            state.clone(),
            "oauth".to_string(),
            "octopus".to_string(),
            "evolve:harness-repair-agent".to_string(),
            "harness:write".to_string(),
        ])
        .unwrap();
        let restored = HarnessState::load(&state_path).unwrap();
        let applied = repair_patch_apply_report(&state_path, &restored, ".".to_string()).unwrap();
        assert_eq!(applied.status, "applied");
        assert!(applied.applied);
        assert!(applied.authorized);
        assert!(applied.command.contains("git apply"));
        assert!(fs::read_to_string(&target)
            .unwrap()
            .contains("provider repair patch"));
        let applied_json = fs::read_to_string(&applied.apply).unwrap();
        assert!(applied_json.contains("\"status\": \"applied\""));
        assert!(applied_json.contains("\"applied\": true"));
        assert!(applied_json.contains("\"authorized\": true"));
        assert!(applied
            .next
            .iter()
            .any(|command| command.contains("repair verify")));

        let mut restored = HarnessState::load(&state_path).unwrap();
        let report = repair_report(&state_path, &mut restored, ".".to_string()).unwrap();
        let plan = report.repair_plan.expect("repair plan report");
        assert_eq!(report.feed.status, Status::Satisfied);
        assert_eq!(plan.status, "patch_applied");
        assert_eq!(plan.repair_patch_apply_status, "applied");
        assert_eq!(plan.repair_patch_apply_applied, "true");
        assert!(plan.grant_command.is_empty());
        assert!(plan.apply_command.is_empty());
        assert_eq!(plan.repair_patch_verify_status, "waiting_for_patch_apply");
        assert_eq!(plan.repair_patch_verify_passed, "false");
        assert!(plan.score_command.is_empty());
        assert!(report
            .next
            .iter()
            .any(|command| command.contains("octopus repair verify")));
        assert!(report.feed.summary.contains("patch_apply=applied"));

        let mut restored = HarnessState::load(&state_path).unwrap();
        let verified =
            repair_patch_verify_report(&state_path, &mut restored, ".".to_string()).unwrap();
        restored.save(&state_path).unwrap();
        assert_eq!(verified.status, "passed");
        assert!(verified.passed);
        assert!(verified
            .command
            .contains("octopus check harness-repair-agent"));
        assert!(verified.check.as_ref().is_some_and(|check| check.passed));
        let verified_json = fs::read_to_string(&verified.verify).unwrap();
        assert!(verified_json.contains("\"status\": \"passed\""));
        assert!(verified_json.contains("\"passed\": true"));
        assert!(verified_json.contains("\"check\""));

        let mut restored = HarnessState::load(&state_path).unwrap();
        let report = repair_report(&state_path, &mut restored, ".".to_string()).unwrap();
        let plan = report.repair_plan.expect("repair plan report");
        assert_eq!(report.feed.status, Status::Satisfied);
        assert_eq!(plan.status, "patch_verified");
        assert_eq!(plan.repair_patch_verify_status, "passed");
        assert_eq!(plan.repair_patch_verify_passed, "true");
        assert!(plan.score_command.contains("repair score"));
        assert!(report.feed.summary.contains("patch_verify=passed"));

        std::env::set_current_dir(&_cwd.original).unwrap();
        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn cli_repair_report_blocks_on_missing_adapter_core() {
        let _env = env_guard();
        let _cwd = CwdGuard::new();
        let dir = std::env::temp_dir().join(format!(
            "octopus-repair-adapter-block-{}",
            std::process::id()
        ));
        let _ = fs::remove_dir_all(&dir);
        fs::create_dir_all(&dir).unwrap();
        std::env::set_current_dir(&dir).unwrap();
        let state_path = dir.join(".octopus/state.json");
        let state = state_path.to_string_lossy().to_string();

        run(vec![
            "--state".to_string(),
            state.clone(),
            "install".to_string(),
            "harness-repair-agent".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state,
            "need".to_string(),
            "execute".to_string(),
            dir.to_string_lossy().to_string(),
        ])
        .unwrap();

        let repair_root = dir.join(".octopus/harness-repair");
        let session_dir = fs::read_dir(&repair_root)
            .unwrap()
            .filter_map(Result::ok)
            .map(|entry| entry.path())
            .find(|path| path.join("REPAIR_PLAN.json").exists())
            .expect("repair session dir");
        fs::write(
            session_dir.join("ADAPTER_CONTEXT.md"),
            "# Adapter Context\n\nstatus: `partial`\nmissing_core: `git`\nprovider_env: `missing`\n",
        )
        .unwrap();

        let mut restored = HarnessState::load(&state_path).unwrap();
        let report = repair_report(&state_path, &mut restored, ".".to_string()).unwrap();
        let plan = report.repair_plan.expect("repair plan report");

        assert_eq!(report.feed.status, Status::Partial);
        assert_eq!(plan.status, "adapter_blocked");
        assert_eq!(plan.adapter_context_status, "partial");
        assert_eq!(plan.adapter_context_missing_core, "git");
        assert!(plan.grant_command.is_empty());
        assert!(plan.apply_command.is_empty());
        assert!(plan.score_command.is_empty());
        assert!(plan.score_commands.is_empty());
        assert!(report.queued.iter().any(|item| item
            .need
            .query
            .contains("install missing core adapters: git")));
        assert!(!report
            .next
            .iter()
            .any(|command| command.contains("harness:write")));
        assert!(!report
            .next
            .iter()
            .any(|command| command.contains("repair score")));

        std::env::set_current_dir(&_cwd.original).unwrap();
        let _ = fs::remove_dir_all(dir);
    }

