    #[test]
    fn provider_matrix_record_writes_four_provider_targets() {
        let _env = env_guard();
        let _cwd = CwdGuard::new();
        let dir =
            std::env::temp_dir().join(format!("octopus-provider-matrix-{}", std::process::id()));
        let path = dir.join("provider-matrix.md");
        let _ = fs::remove_dir_all(&dir);
        fs::create_dir_all(&dir).unwrap();
        std::env::set_current_dir(&dir).unwrap();
        std::process::Command::new("git")
            .args(["init", "-q"])
            .status()
            .unwrap();
        std::process::Command::new("git")
            .args(["config", "user.email", "octopus@example.invalid"])
            .status()
            .unwrap();
        std::process::Command::new("git")
            .args(["config", "user.name", "Octopus Test"])
            .status()
            .unwrap();
        fs::write("README.md", "octopus\n").unwrap();
        std::process::Command::new("git")
            .args(["add", "README.md"])
            .status()
            .unwrap();
        std::process::Command::new("git")
            .args(["commit", "-q", "-m", "init"])
            .status()
            .unwrap();

        let report = write_provider_matrix_record(&path).unwrap();
        let content = fs::read_to_string(&path).unwrap();

        assert_eq!(report.targets.len(), 4);
        assert_eq!(report.env_files.len(), 4);
        assert!(report.env_files.iter().all(|item| item.status == "created"));
        assert!(dir.join(".octopus/providers/codex.env").exists());
        assert!(dir.join(".octopus/providers/openai.env").exists());
        assert!(dir.join(".octopus/providers/local.env").exists());
        assert!(dir.join(".octopus/providers/gateway.env").exists());
        let second = write_provider_matrix_record(&path).unwrap();
        assert!(second.env_files.iter().all(|item| item.status == "exists"));
        assert!(content.contains("# Provider Matrix Record"));
        assert!(content.contains("Codex OAuth"));
        assert!(content.contains("API-key cloud"));
        assert!(content.contains("Local model"));
        assert!(content.contains("Gateway/router"));
        assert!(content.contains("Enable: `OCTOPUS_CODEX_OK=1`"));
        assert!(content.contains("export OCTOPUS_CODEX_OK=1"));
        assert!(content.contains("octopus provider check OCTOPUS_MATRIX_CODEX"));
        assert!(content.contains("octopus brain --goal --live"));
        assert!(content.contains("OCTOPUS_LLM_MANIFEST=1"));
        assert!(content.contains("OCTOPUS_LLM_EVOLVE=1"));
        let audit = check_provider_matrix_record(&path).unwrap();
        assert!(!audit.passed);

        let filled = content
            .replace("- Date:", "- Date: 2026-06-28")
            .replace("- Tester:", "- Tester: local tester")
            .replace("- Machine:", "- Machine: local machine")
            .replace("- OS:", "- OS: local os")
            .replace("- Shell:", "- Shell: zsh")
            .replace("- Goal chat:", "- Goal chat: pass")
            .replace("- Clean brain:", "- Clean brain: pass")
            .replace("- Tentacle planning:", "- Tentacle planning: pass")
            .replace("- Harness evolution:", "- Harness evolution: pass")
            .replace("- Provider check:", "- Provider check: pass")
            .replace("- Pass or fail:", "- Pass or fail: pass");
        fs::write(&path, filled).unwrap();
        let audit = check_provider_matrix_record(&path).unwrap();
        assert!(audit.passed);
        let third = write_provider_matrix_record(&path).unwrap();
        assert!(third.env_files.iter().all(|item| item.status == "exists"));
        let audit = check_provider_matrix_record(&path).unwrap();
        assert!(audit.passed);

        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn provider_matrix_run_writes_skipped_targets_without_live_env() {
        let _env = env_guard();
        for key in [
            "OCTOPUS_CODEX_OK",
            "OCTOPUS_OPENAI_OK",
            "OCTOPUS_LOCAL_OK",
            "OCTOPUS_GATEWAY_OK",
        ] {
            std::env::remove_var(key);
        }
        let dir = std::env::temp_dir().join(format!(
            "octopus-provider-matrix-run-{}",
            std::process::id()
        ));
        let path = dir.join("provider-matrix.md");
        let state_path = dir.join("state.json");
        let _ = fs::remove_dir_all(&dir);
        fs::create_dir_all(&dir).unwrap();

        let report =
            run_provider_matrix_record(&HarnessState::default(), &state_path, &path).unwrap();
        let content = fs::read_to_string(&path).unwrap();

        assert_eq!(report.results.len(), 4);
        assert!(!report.audit.passed);
        assert!(content.contains("- Provider check: skipped: set OCTOPUS_CODEX_OK=1 to run"));
        assert!(content.contains("- Clean brain: skipped: set OCTOPUS_CODEX_OK=1 to run"));
        assert!(content.contains("- Goal chat: fail: 0/4 targets passed"));
        assert!(content.contains("- Pass or fail: fail: one or more provider targets"));

        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn benchmark_record_requires_five_minimal_cases() {
        let _env = env_guard();
        let _cwd = CwdGuard::new();
        let dir =
            std::env::temp_dir().join(format!("octopus-benchmark-record-{}", std::process::id()));
        let path = dir.join("benchmark-evidence.md");
        let _ = fs::remove_dir_all(&dir);
        fs::create_dir_all(&dir).unwrap();
        std::env::set_current_dir(&dir).unwrap();
        std::process::Command::new("git")
            .args(["init", "-q"])
            .status()
            .unwrap();
        std::process::Command::new("git")
            .args(["config", "user.email", "octopus@example.invalid"])
            .status()
            .unwrap();
        std::process::Command::new("git")
            .args(["config", "user.name", "Octopus Test"])
            .status()
            .unwrap();
        fs::write("README.md", "octopus\n").unwrap();
        std::process::Command::new("git")
            .args(["add", "README.md"])
            .status()
            .unwrap();
        std::process::Command::new("git")
            .args(["commit", "-q", "-m", "init"])
            .status()
            .unwrap();

        let head = git_short_head();
        let report =
            write_benchmark_record(&path, env!("CARGO_PKG_VERSION"), head.clone(), shell_arg)
                .unwrap();
        let content = fs::read_to_string(&path).unwrap();

        assert_eq!(report.cases.len(), 5);
        assert!(content.contains("# Benchmark Evidence"));
        assert!(content.contains("SWE-Bench verify mini 1"));
        assert!(content.contains("SWE-Bench verify mini 2"));
        assert!(content.contains("SWE-Bench verify mini 3"));
        assert!(content.contains("Claw-SWE-Bench simplest"));
        assert!(content.contains("Wild-Claw-Bench simplest"));
        let audit = check_benchmark_record(&path, head.clone()).unwrap();
        assert!(!audit.passed);
        assert!(
            audit
                .checks
                .iter()
                .any(|check| check.id == "benchmark_swe_bench_verify_mini_1"
                    && check.status == "fail")
        );

        let filled = content
            .replace("- Date:", "- Date: 2026-06-28")
            .replace("- Tester:", "- Tester: local tester")
            .replace("- Machine:", "- Machine: local machine")
            .replace("- OS:", "- OS: local os")
            .replace("- Case id:", "- Case id: recorded-case")
            .replace("- Command:", "- Command: octopus need verify recorded-case")
            .replace("- Pass or fail:", "- Pass or fail: pass")
            .replace(
                "- Output summary:",
                "- Output summary: passed with compact Feed",
            )
            .replace(
                "- Artifact path:",
                "- Artifact path: artifacts/recorded-case.log",
            );
        fs::write(&path, filled).unwrap();
        fs::create_dir_all(dir.join("artifacts")).unwrap();
        fs::write(dir.join("artifacts/recorded-case.log"), "passed\n").unwrap();
        let audit = check_benchmark_record(&path, head).unwrap();
        assert!(audit.passed);

        std::env::set_current_dir(&_cwd.original).unwrap();
        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn bridge_limits_user_mutation_to_goal_surface() {
        assert_eq!(
            bridge_command_name(&[
                "--state".to_string(),
                "state.json".to_string(),
                "--json".to_string(),
                "doctor".to_string()
            ]),
            Some("doctor")
        );
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "chat".to_string(),
            "make this repo easier".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "goal".to_string(),
            "set".to_string(),
            "make this repo easier".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "goal".to_string(),
            "refine".to_string(),
            "prefer clean Needs".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "brain".to_string(),
            "--goal".to_string(),
            "--session".to_string(),
            "make this repo easier".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "brain".to_string(),
            "--goal".to_string(),
            "--save".to_string(),
            "make this repo easier".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "first-run".to_string(),
            "--live".to_string(),
            "make this repo easier".to_string()
        ]));

        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "doctor".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "report".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "download".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--json".to_string(),
            "provider".to_string(),
            "status".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--json".to_string(),
            "preflight".to_string(),
            "--live".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "pet".to_string(),
            "harness".to_string()
        ]));
        assert!(bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "starter".to_string(),
            "make this repo easier".to_string()
        ]));

        assert!(!bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "need".to_string(),
            "observe".to_string(),
            ".".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "brain".to_string(),
            "--agenda".to_string(),
            "--save".to_string(),
            "what matters next".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "brain".to_string(),
            "--session".to_string(),
            "what should the brain ask next".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "repair".to_string(),
            ".".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "evolve".to_string(),
            "apply".to_string(),
            "swe-agent".to_string(),
            "03-runtime-code".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--json".to_string(),
            "provider".to_string(),
            "save".to_string(),
            "openai".to_string(),
            "OCTOPUS_LLM".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--json".to_string(),
            "provider".to_string(),
            "check".to_string(),
            "OCTOPUS_LLM".to_string(),
            "custom message".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "starter".to_string(),
            "feedback".to_string(),
            "swe-agent".to_string(),
            "accepted".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "pet".to_string(),
            "image".to_string(),
            "harness".to_string(),
            "/tmp/octopus.svg".to_string()
        ]));
        assert!(!bridge_command_allowed(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "preflight".to_string(),
            "record".to_string(),
            "append".to_string()
        ]));
        let denied = run_bridge_command(&[
            "--state".to_string(),
            "state.json".to_string(),
            "--json".to_string(),
            "need".to_string(),
            "observe".to_string(),
            ".".to_string(),
        ])
        .unwrap();
        assert!(!denied.ok);
        assert_eq!(
            denied.policy.as_deref(),
            Some("user_writes_brain_goal_only")
        );
        assert!(denied.stderr.contains("brain-goal"));
        assert!(denied
            .suggested_args
            .iter()
            .any(|args| args.iter().any(|arg| arg == "--goal")));
        assert_eq!(
            http_content_length("POST /api/run HTTP/1.1\r\nContent-Length: 42\r\n").unwrap(),
            42
        );
    }

    #[test]
    fn check_report_runs_manifest_checks() {
        let _env = env_guard();
        let _cwd = CwdGuard::new();
        std::env::set_current_dir(crate::repo_root()).unwrap();

        let report = check_report("json-feed", None).unwrap();

        assert_eq!(report.id, "json-feed");
        assert_eq!(report.source_kind, "manifest");
        assert!(report.passed);
        assert!(report
            .results
            .iter()
            .any(|result| result.command.contains("py_compile")));

        let selected = check_report("computer-use-agent", Some(1)).unwrap();
        assert_eq!(selected.results.len(), 1);
        assert!(selected.results[0].command.contains("window_status"));
        let repair = check_report("harness-repair-agent", None).unwrap();
        assert!(repair.passed);
        assert!(repair
            .results
            .iter()
            .any(|result| result.command.contains("repair_session.sh")));
        assert!(check_report("json-feed", Some(99))
            .unwrap_err()
            .contains("out of range"));
    }

