    #[test]
    fn pet_auto_state_tracks_harness_state() {
        let root = Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../..")
            .join("tentacles");
        let state_path = Path::new("state.json");
        let mut state = HarnessState::default();

        assert_eq!(
            pet_report_for_state(&state, state_path, "auto")
                .unwrap()
                .state,
            "blocked"
        );

        state.install_manifest(root, "swe-agent").unwrap();
        assert_eq!(
            pet_report_for_state(&state, state_path, "auto")
                .unwrap()
                .state,
            "heartbeat"
        );

        state.memory.remember("use memory beat");
        assert_eq!(
            pet_report_for_state(&state, state_path, "auto")
                .unwrap()
                .state,
            "memory"
        );

        let mut feed = Feed::satisfied(
            &Need::new(NeedKind::Observe, "repo state"),
            "observed repo",
            "swe-agent",
        );
        feed.metadata
            .insert("tentacle".to_string(), "swe-agent".to_string());
        state.routes.learn(&feed);
        assert_eq!(
            pet_report_for_state(&state, state_path, "auto")
                .unwrap()
                .state,
            "harness"
        );

        let mut goal = Goal::new("ship octopus");
        goal.status = GoalStatus::Satisfied;
        state.goal = Some(goal);
        assert_eq!(
            pet_report_for_state(&state, state_path, "auto")
                .unwrap()
                .state,
            "success"
        );

        state.goal.as_mut().unwrap().status = GoalStatus::Blocked;
        assert_eq!(
            pet_report_for_state(&state, state_path, "auto")
                .unwrap()
                .state,
            "blocked"
        );
    }

    #[test]
    fn pet_auto_state_prefers_recent_action_event() {
        let root = Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../..")
            .join("tentacles");
        let state_path = Path::new("state.json");
        let mut state = HarnessState::default();
        state.install_manifest(root, "swe-agent").unwrap();
        state.record_pet_event(
            "success",
            "swe-agent",
            "observed repo from feed",
            Status::Satisfied,
        );

        let report = pet_report_for_state(&state, state_path, "auto").unwrap();

        assert_eq!(report.state, "success");
        assert_eq!(report.fallback, "🟩");
        assert_eq!(report.event_source.as_deref(), Some("swe-agent"));
        assert_eq!(
            report.event_summary.as_deref(),
            Some("observed repo from feed")
        );
        assert!(report.target.contains("docs/pet.html?state=success"));

        state.record_pet_event("not-a-pet-state", "manual", "bad state", Status::Failed);
        let report = pet_report_for_state(&state, state_path, "auto").unwrap();

        assert_eq!(report.state, "heartbeat");
        assert!(report.event_source.is_none());
    }

    #[test]
    fn cli_status_and_doctor_commands_run() {
        let _env = env_guard();
        let path =
            std::env::temp_dir().join(format!("octopus-status-state-{}.json", std::process::id()));
        let state = path.to_string_lossy().to_string();
        let _ = fs::remove_file(&path);

        run(vec![
            "--state".to_string(),
            state.clone(),
            "pet".to_string(),
            "memory".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "pet".to_string(),
            "success".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "status".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--lang".to_string(),
            "zh".to_string(),
            "doctor".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "doctor".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "install".to_string(),
            "swe-agent".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "status".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "report".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "report".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "preflight".to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "preflight".to_string(),
        ])
        .unwrap();
        let script_path = path.with_file_name("preflight.sh");
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "preflight".to_string(),
            "script".to_string(),
            script_path.to_string_lossy().to_string(),
        ])
        .unwrap();
        let record_path = path.with_file_name("real-machine-record.md");
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "preflight".to_string(),
            "record".to_string(),
            record_path.to_string_lossy().to_string(),
        ])
        .unwrap();
        run(vec![
            "--state".to_string(),
            state.clone(),
            "--json".to_string(),
            "preflight".to_string(),
            "record".to_string(),
            "check".to_string(),
            record_path.to_string_lossy().to_string(),
        ])
        .unwrap();

        let loaded = HarnessState::load(&path).unwrap();
        let report = product_report(&loaded, Path::new(&state)).unwrap();
        assert!(report
            .capabilities
            .iter()
            .any(|item| item.id == "clean_brain"));
        assert!(report.boundary.ok);
        assert!(report
            .capabilities
            .iter()
            .any(|item| item.id == "core_harness_boundary"));
        assert!(report
            .capabilities
            .iter()
            .any(|item| item.id == "harness_self_repair"));
        assert!(report
            .gaps
            .iter()
            .any(|item| item.id == "provider_feedback"));
        let preflight = preflight_report(&loaded, Path::new(&state), false).unwrap();
        assert!(!preflight.release_ready);
        assert!(preflight.summary.required_total >= 10);
        assert!(preflight.summary.required_passed < preflight.summary.required_total);
        assert!(preflight
            .summary
            .blockers
            .iter()
            .any(|item| item.id == "live_provider"));
        assert!(preflight
            .summary
            .next_steps
            .iter()
            .any(|item| item.contains("octopus benchmark record")));
        assert!(preflight
            .checks
            .iter()
            .any(|item| item.id == "bridge_goal_surface" && item.status == "pass"));
        assert!(preflight
            .checks
            .iter()
            .any(|item| item.id == "core_harness_boundary" && item.status == "pass"));
        assert!(preflight
            .checks
            .iter()
            .any(|item| item.id == "field_parallel_pool"
                && item.status == "pass"
                && item.required));
        assert!(preflight
            .checks
            .iter()
            .any(|item| item.id == "live_provider" && item.status == "skipped"));
        assert!(preflight
            .checks
            .iter()
            .any(|item| item.id == "benchmark_evidence" && item.status == "fail"));
        assert!(preflight
            .checks
            .iter()
            .any(|item| { item.id == "feedback_data" && item.next.contains("first-run") }));
        assert!(preflight
            .next
            .iter()
            .any(|item| item.contains("preflight --live")));
        let script = fs::read_to_string(&script_path).unwrap();
        assert!(script.contains("octopus --state \"$STATE\" first-run"));
        assert!(script.contains("octopus --state \"$STATE\" fields summary"));
        assert!(script.contains("OCTOPUS_PREFLIGHT_LIVE"));
        let record = fs::read_to_string(&record_path).unwrap();
        assert!(record.contains("# Real-Machine Record"));
        assert!(record.contains("Package version"));
        assert!(record.contains("first-run"));
        assert!(record.contains("\"$OCTOPUS\" download"));
        assert!(record.contains("--json download"));
        assert!(record.contains("/download.json"));
        assert!(record.contains("/install.sh"));
        assert!(record.contains("Download artifacts"));
        assert!(record.contains("Field pool"));
        assert!(record.contains("bridge_goal_surface"));
        assert!(record.contains("provider matrix"));
        assert!(record.contains("provider matrix run"));
        assert!(record.contains("provider matrix check"));
        assert!(record.contains("fields summary"));
        assert!(record.contains("benchmark record"));
        assert!(record.contains("benchmark check"));
        assert!(record.contains("Benchmark evidence"));
        assert!(record.contains("preflight --live"));
        assert!(record.contains("start --check"));
        assert!(record.contains("self-iterate pr"));
        let audit = check_preflight_record(&record_path).unwrap();
        assert!(!audit.passed);
        let filled = record
            .replace("- Date:", "- Date: 2026-06-27")
            .replace("- Tester:", "- Tester: local")
            .replace("- Machine:", "- Machine: mac")
            .replace("- OS:", "- OS: macOS")
            .replace("- Shell:", "- Shell: zsh")
            .replace("- Rust:", "- Rust: stable")
            .replace("- Python:", "- Python: 3.14")
            .replace("- Install and doctor:", "- Install and doctor: pass")
            .replace("- Download artifacts:", "- Download artifacts: pass")
            .replace("- Core loop:", "- Core loop: pass")
            .replace("- Product bridge:", "- Product bridge: pass")
            .replace("- Field pool:", "- Field pool: pass")
            .replace("- Start/app:", "- Start/app: pass")
            .replace("- Live provider:", "- Live provider: pass")
            .replace("- Benchmark evidence:", "- Benchmark evidence: pass")
            .replace("- PR dry run:", "- PR dry run: pass")
            .replace("- Pass or fail:", "- Pass or fail: pass");
        fs::write(&record_path, filled).unwrap();
        let audit = check_preflight_record(&record_path).unwrap();
        assert!(audit.passed);
        let log_path = path.with_file_name("real-machine-test.md");
        let append = append_preflight_record(&record_path, &log_path).unwrap();
        assert!(append.appended);
        assert!(!append.already_present);
        let appended_log = fs::read_to_string(&log_path).unwrap();
        assert!(appended_log.contains("# Real-Machine Record"));
        assert!(appended_log.contains("Pass or fail: pass"));
        let append_again = append_preflight_record(&record_path, &log_path).unwrap();
        assert!(!append_again.appended);
        assert!(append_again.already_present);

        let content = fs::read_to_string(&path).unwrap();
        assert!(content.contains("swe-agent"));
        let _ = fs::remove_file(path);
        let _ = fs::remove_file(script_path);
        let _ = fs::remove_file(log_path);
    }

