    #[test]
    fn update_report_defaults_to_dry_run_command() {
        let report = update_report(false);

        assert_eq!(report.current_version, env!("CARGO_PKG_VERSION"));
        assert!(!report.run);
        assert_eq!(report.status, "ready");
        assert!(report.shell.contains("cargo install --git"));
        assert_eq!(report.download_command, "octopus download");
        assert!(report.command.contains(&"octopus-core".to_string()));
        assert!(report.next.contains(&"octopus download".to_string()));
        assert!(report.next.contains(&"octopus update --run".to_string()));
        assert!(report.next.contains(&"octopus start --open".to_string()));
    }

    #[test]
    fn download_report_exposes_install_update_and_pages_paths() {
        let report = download_report();

        assert_eq!(report.current_version, env!("CARGO_PKG_VERSION"));
        assert_eq!(report.repository, "https://github.com/dangoZhang/Octopus");
        assert!(report.source_archive_url.ends_with("/main.zip"));
        assert!(report.install_script_url.ends_with("/install.sh"));
        assert!(report.install_script_shell.starts_with("curl -fsSL"));
        assert!(report.install_script_shell.ends_with("| sh"));
        assert!(report.install.shell.contains("cargo"));
        assert!(report.install.shell.contains("octopus-core"));
        assert_eq!(report.update.shell, "octopus update --run");
        assert_eq!(report.verify[0].shell, "octopus --version");
        assert_eq!(
            report.verify[1].shell,
            "octopus start --check '127.0.0.1:18765'"
        );
        assert!(report
            .docs
            .iter()
            .any(|link| link.url.ends_with("/quickstart.html")));
        assert!(report.next.contains(&"octopus --version".to_string()));
        assert!(report
            .next
            .contains(&"octopus start --check 127.0.0.1:18765".to_string()));
        assert!(report.next.contains(&"octopus start --open".to_string()));
    }

    #[test]
    fn install_report_exposes_manifest_grants_checks_and_next_steps() {
        let root = Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../..")
            .join("tentacles");
        let state_path = Path::new(".octopus/state with space.json");
        let mut state = HarnessState::default();
        state
            .install_profile("computer-use-agent")
            .expect("profile should install");
        let installed = state
            .install_manifest(&root, "computer-use-agent")
            .expect("manifest should install");
        let profile = default_tentacle_profiles()
            .into_iter()
            .find(|profile| profile.id == "computer-use-agent");
        let manifest = load_tentacle_manifests(&root)
            .unwrap()
            .into_iter()
            .find(|loaded| loaded.manifest.id == "computer-use-agent");

        let report = install_report(
            "computer-use-agent",
            state_path,
            true,
            Some(&installed),
            profile.as_ref(),
            manifest.as_ref(),
            &state,
        );

        assert_eq!(report.source_kind, "profile+manifest");
        assert!(report
            .tools
            .iter()
            .any(|tool| tool == "clipboard_read:shell"));
        assert!(report.runtimes.iter().any(|runtime| runtime == "shell"));
        assert!(report
            .checks
            .iter()
            .any(|check| check.contains("OCTOPUS_CLIPBOARD_DRY_RUN=1")));
        assert!(report.grants.iter().any(|grant| {
            !grant.active
                && grant.scope == "tool:computer-use-agent"
                && grant
                    .permissions
                    .iter()
                    .any(|permission| permission == "tool:observe")
                && grant
                    .permissions
                    .iter()
                    .any(|permission| permission == "tool:ui")
                && grant.command.contains("'.octopus/state with space.json'")
                && grant.command.contains("'tool:observe'")
                && grant.command.contains("'tool:ui'")
        }));
        assert!(report
            .next
            .iter()
            .any(|command| { command.contains("think computer-use-agent observe .") }));
        assert!(report
            .next
            .iter()
            .any(|command| { command.contains("need observe .") }));
    }

